import{_ as n}from"./plugin-vue_export-helper-c27b6911.js";import{o as s,c as a,e as t}from"./app-8181ed57.js";const p={},e=t(`<h2 id="是类还是函数" tabindex="-1"><a class="header-anchor" href="#是类还是函数" aria-hidden="true">#</a> 是类还是函数</h2><p>几乎所有的教程都告诉你 int() 是 python 的内置函数，然而当你看到 int 的定义，发现它竟然是类</p><div class="language-python line-numbers-mode" data-ext="py"><pre class="language-python"><code><span class="token keyword">class</span> <span class="token class-name">int</span><span class="token punctuation">(</span><span class="token builtin">object</span><span class="token punctuation">)</span><span class="token punctuation">:</span>
    <span class="token keyword">pass</span>
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div></div></div><p>不只是 int(), 还有 float()， bool()， str()，很多你以为是函数但实际上却是类，但是呢，当你使用它们时完全察觉不出它们有什么不同，本文不是要和你讨论类和函数，而是要讨论学习 callable</p><h2 id="什么是-callable" tabindex="-1"><a class="header-anchor" href="#什么是-callable" aria-hidden="true">#</a> 什么是 callable</h2><p>一个可 callable 的对象是指可以被调用执行的对象，并且可以传入参数， 用另一个简单的描述方式，只要可以在一个对象的后面使用小括号来执行代码，那么这个对象就是 callable 对象。下面列举 callable 对象的种类：</p><ol><li>函数</li><li>类</li><li>类里的函数</li><li>实现了__call__方法的实例对象</li></ol><h3 id="函数" tabindex="-1"><a class="header-anchor" href="#函数" aria-hidden="true">#</a> 函数</h3><div class="language-python line-numbers-mode" data-ext="py"><pre class="language-python"><code><span class="token keyword">def</span> <span class="token function">test</span><span class="token punctuation">(</span><span class="token punctuation">)</span><span class="token punctuation">:</span>
    <span class="token keyword">print</span><span class="token punctuation">(</span><span class="token string">&#39;ok&#39;</span><span class="token punctuation">)</span>

<span class="token keyword">print</span><span class="token punctuation">(</span><span class="token builtin">callable</span><span class="token punctuation">(</span>test<span class="token punctuation">)</span><span class="token punctuation">)</span>   <span class="token comment"># True</span>
test<span class="token punctuation">(</span><span class="token punctuation">)</span>  <span class="token comment"># ok</span>
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><p>函数是 python 里的一等公民，函数是可调用对象，使用 callable 函数可以证明这一点</p><h3 id="类" tabindex="-1"><a class="header-anchor" href="#类" aria-hidden="true">#</a> 类</h3><div class="language-python line-numbers-mode" data-ext="py"><pre class="language-python"><code><span class="token keyword">class</span> <span class="token class-name">Stu</span><span class="token punctuation">(</span><span class="token builtin">object</span><span class="token punctuation">)</span><span class="token punctuation">:</span>
    <span class="token keyword">def</span> <span class="token function">__init__</span><span class="token punctuation">(</span>self<span class="token punctuation">,</span> name<span class="token punctuation">)</span><span class="token punctuation">:</span>
        self<span class="token punctuation">.</span>name <span class="token operator">=</span> name


<span class="token keyword">print</span><span class="token punctuation">(</span><span class="token builtin">callable</span><span class="token punctuation">(</span>Stu<span class="token punctuation">)</span><span class="token punctuation">)</span>     <span class="token comment"># True</span>
<span class="token keyword">print</span><span class="token punctuation">(</span>Stu<span class="token punctuation">(</span><span class="token string">&#39;小明&#39;</span><span class="token punctuation">)</span><span class="token punctuation">.</span>name<span class="token punctuation">)</span>   <span class="token comment"># 小明</span>
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><p>在其他编程语言里，类与函数可以说是两个完全不搭的东西，但在 python 里，都是可调用对象</p><h3 id="类里的方法" tabindex="-1"><a class="header-anchor" href="#类里的方法" aria-hidden="true">#</a> 类里的方法</h3><p>类里的方法也是用 def 定义的，本质上也是函数</p><div class="language-python line-numbers-mode" data-ext="py"><pre class="language-python"><code><span class="token keyword">from</span> inspect <span class="token keyword">import</span> isfunction<span class="token punctuation">,</span> ismethod


<span class="token keyword">class</span> <span class="token class-name">Stu</span><span class="token punctuation">(</span><span class="token builtin">object</span><span class="token punctuation">)</span><span class="token punctuation">:</span>
    <span class="token keyword">def</span> <span class="token function">__init__</span><span class="token punctuation">(</span>self<span class="token punctuation">,</span> name<span class="token punctuation">)</span><span class="token punctuation">:</span>
        self<span class="token punctuation">.</span>name <span class="token operator">=</span> name

    <span class="token keyword">def</span> <span class="token function">run</span><span class="token punctuation">(</span>self<span class="token punctuation">)</span><span class="token punctuation">:</span>
        <span class="token keyword">print</span><span class="token punctuation">(</span><span class="token string">&#39;{name} is running&#39;</span><span class="token punctuation">.</span><span class="token builtin">format</span><span class="token punctuation">(</span>name<span class="token operator">=</span>self<span class="token punctuation">.</span>name<span class="token punctuation">)</span><span class="token punctuation">)</span>

<span class="token keyword">print</span><span class="token punctuation">(</span>isfunction<span class="token punctuation">(</span>Stu<span class="token punctuation">.</span>run<span class="token punctuation">)</span><span class="token punctuation">)</span>     <span class="token comment"># True</span>
stu <span class="token operator">=</span> Stu<span class="token punctuation">(</span><span class="token string">&quot;小明&quot;</span><span class="token punctuation">)</span>
stu<span class="token punctuation">.</span>run<span class="token punctuation">(</span><span class="token punctuation">)</span>        <span class="token comment"># 小明 is running</span>
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><p>使用 isfunction 函数可以判断一个对象是否是函数，run 方法也是可调用对象</p><h3 id="实现了-call-方法的实例对象" tabindex="-1"><a class="header-anchor" href="#实现了-call-方法的实例对象" aria-hidden="true">#</a> 实现了<code>__call__</code>方法的实例对象</h3><div class="language-python line-numbers-mode" data-ext="py"><pre class="language-python"><code><span class="token keyword">class</span> <span class="token class-name">Stu</span><span class="token punctuation">(</span><span class="token builtin">object</span><span class="token punctuation">)</span><span class="token punctuation">:</span>

    <span class="token keyword">def</span> <span class="token function">__init__</span><span class="token punctuation">(</span>self<span class="token punctuation">,</span> name<span class="token punctuation">)</span><span class="token punctuation">:</span>
        self<span class="token punctuation">.</span>name <span class="token operator">=</span> name

    <span class="token keyword">def</span> <span class="token function">__call__</span><span class="token punctuation">(</span>self<span class="token punctuation">,</span> <span class="token operator">*</span>args<span class="token punctuation">,</span> <span class="token operator">**</span>kwargs<span class="token punctuation">)</span><span class="token punctuation">:</span>
        self<span class="token punctuation">.</span>run<span class="token punctuation">(</span><span class="token punctuation">)</span>

    <span class="token keyword">def</span> <span class="token function">run</span><span class="token punctuation">(</span>self<span class="token punctuation">)</span><span class="token punctuation">:</span>
        <span class="token keyword">print</span><span class="token punctuation">(</span><span class="token string">&#39;{name} is running&#39;</span><span class="token punctuation">.</span><span class="token builtin">format</span><span class="token punctuation">(</span>name<span class="token operator">=</span>self<span class="token punctuation">.</span>name<span class="token punctuation">)</span><span class="token punctuation">)</span>

stu <span class="token operator">=</span> Stu<span class="token punctuation">(</span><span class="token string">&#39;小明&#39;</span><span class="token punctuation">)</span>
<span class="token keyword">print</span><span class="token punctuation">(</span><span class="token builtin">callable</span><span class="token punctuation">(</span>stu<span class="token punctuation">)</span><span class="token punctuation">)</span>    <span class="token comment"># True</span>
stu<span class="token punctuation">(</span><span class="token punctuation">)</span>                   <span class="token comment"># 小明 is running</span>
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><p>当你执行 <code>stu()</code> 时，与调用一个函数有着完全一致的体验，如果不告诉你 stu 是一个类的实例对象，你还以为 stu 就是一个函数。</p>`,20),c=[e];function o(l,i){return s(),a("div",null,c)}const r=n(p,[["render",o],["__file","python中的callable概念.html.vue"]]);export{r as default};
